from flask import Flask, request, jsonify, session, abort
import os
import pyotp

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Mock database for users and MFA status
users_db = {
    'user1': {'password': 'password1', 'mfa_enabled': True},
    'user2': {'password': 'password2', 'mfa_enabled': False}
}

@app.route('/login', methods=['POST'])
def login():
    username = request.form['username']
    password = request.form['password']

    if username in users_db and users_db[username]['password'] == password:
        session['user'] = username
        if users_db[username]['mfa_enabled']:
            return jsonify({'message': 'MFA required', 'type': 'mfa_required'}), 401
        else:
            return jsonify({'message': 'Login successful'}), 200
    else:
        abort(401, description='Invalid credentials')

@app.route('/verify_otp', methods=['POST'])
def verify_otp():
    username = session.get('user')
    if not username:
        abort(401, description='Unauthorized')

    otp = request.form['otp']
    user = users_db[username]
    totp = pyotp.TOTP(user['mfa_secret'])

    if totp.verify(otp):
        return jsonify({'message': 'Login successful'}), 200
    else:
        abort(401, description='Invalid OTP')

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    username = request.form['username']
    password = request.form['password']

    if username in users_db and users_db[username]['password'] == password:
        return jsonify({'message': 'Login successful'}), 200
    else:
        abort(401, description='Invalid credentials')

if __name__ == '__main__':
    app.run(debug=True)